const buildCopperKnobDescription = (entry) => {
  const name = String(entry?.name || '');
  const foot = entry?.foot;

  if (!(foot === 'L' || foot === 'R')) return null;

  const side = foot === 'L' ? 'left' : 'right';
  const other = foot === 'L' ? 'right' : 'left';
  const turnDir = /\bLeft\b/i.test(name) ? 'left' : /\bRight\b/i.test(name) ? 'right' : side;

  if (/^Nightclub (Two Step|Basic)\b/i.test(name)) {
    return `Big step ${side} to ${side} side, rock ${other} slightly behind ${side}, recover onto ${side}.`;
  }

  if (/^Behind Side Cross Point\b/i.test(name)) {
    return `Step ${side} behind ${other}, step ${other} to ${other} side, cross ${side} over ${other}, point ${other} to ${other} side.`;
  }

  if (/^Behind Side Cross Touch\b/i.test(name)) {
    return `Step ${side} behind ${other}, step ${other} to ${other} side, cross ${side} over ${other}, touch ${other} beside ${side}.`;
  }

  if (/^Behind Side Cross Hold\b/i.test(name)) {
    return `Step ${side} behind ${other}, step ${other} to ${other} side, cross ${side} over ${other}, hold.`;
  }

  if (/^Behind Side Cross Sweep\b/i.test(name)) {
    return `Step ${side} behind ${other}, step ${other} to ${other} side, cross ${side} over ${other}, sweep ${other} from back to front.`;
  }

  if (/^Behind Side Cross 1\/4 Turn\b/i.test(name)) {
    return `Step ${side} behind ${other}, step ${other} to ${other} side, turn 1/4 ${turnDir} crossing ${side} over ${other}.`;
  }

  if (/^Behind Side Cross Rock\b/i.test(name)) {
    return `Step ${side} behind ${other}, step ${other} to ${other} side, cross rock ${side} over ${other}, recover onto ${other}.`;
  }

  if (/^(Syncopated )?Behind Side Cross\b/i.test(name)) {
    return `Step ${side} behind ${other}, step ${other} to ${other} side, cross ${side} over ${other}.`;
  }

  if (/^Sailor Step\b/i.test(name)) {
    return `Cross ${side} behind ${other}, step ${other} to ${other} side, step ${side} in place.`;
  }

  if (/^Sailor Cross\b/i.test(name)) {
    return `Cross ${side} behind ${other}, step ${other} to ${other} side, cross ${side} over ${other}.`;
  }

  if (/^Sailor Turn\b/i.test(name)) {
    return `Cross ${side} behind ${other} turning ${turnDir}, step ${other} to ${other} side, step ${side} slightly forward.`;
  }

  if (/^Grapevine Turn Left\b/i.test(name)) {
    return 'Step left to left side, cross right behind left, step left turning left.';
  }

  if (/^Grapevine Turn Right\b/i.test(name)) {
    return 'Step right to right side, cross left behind right, step right turning right.';
  }

  if (/^Grapevine Left\b/i.test(name)) {
    return 'Step left to left side, cross right behind left, step left to left side.';
  }

  if (/^Grapevine Right\b/i.test(name)) {
    return 'Step right to right side, cross left behind right, step right to right side.';
  }

  if (/^Weave Left\b/i.test(name)) {
    return 'Cross right over left, step left to left side, cross right behind left, step left to left side.';
  }

  if (/^Weave Right\b/i.test(name)) {
    return 'Cross left over right, step right to right side, cross left behind right, step right to right side.';
  }

  if (/^Rolling Vine Left\b/i.test(name)) {
    return 'Turn 1/4 left stepping left forward, turn 1/2 left stepping right back, turn 1/4 left stepping left to left side.';
  }

  if (/^Rolling Vine Right\b/i.test(name)) {
    return 'Turn 1/4 right stepping right forward, turn 1/2 right stepping left back, turn 1/4 right stepping right to right side.';
  }

  if (/^Jazz Box Turn\b/i.test(name)) {
    return `Cross ${side} over ${other}, turn ${turnDir} stepping ${other} back, step ${side} to ${side} side, step ${other} slightly forward.`;
  }

  if (/^Jazz Box Cross\b/i.test(name)) {
    return `Cross ${side} over ${other}, step ${other} back, step ${side} to ${side} side, cross ${other} over ${side}.`;
  }

  if (/^Jazz Box\b/i.test(name)) {
    return `Cross ${side} over ${other}, step ${other} back, step ${side} to ${side} side, step ${other} beside ${side}.`;
  }

  if (/^Mambo Forward\b/i.test(name)) {
    return `Rock ${side} forward, recover onto ${other}, step ${side} beside ${other}.`;
  }

  if (/^Mambo Back\b/i.test(name)) {
    return `Rock ${side} back, recover onto ${other}, step ${side} beside ${other}.`;
  }

  if (/^Mambo Side\b/i.test(name)) {
    return `Rock ${side} to ${side} side, recover onto ${other}, step ${side} beside ${other}.`;
  }

  if (/^Mambo Cross\b/i.test(name)) {
    return `Rock ${side} to ${side} side, recover onto ${other}, cross ${side} over ${other}.`;
  }

  if (/^Coaster Step Forward\b/i.test(name)) {
    return `Step ${side} forward, close ${other} beside ${side}, step ${side} back.`;
  }

  if (/^Coaster Step Back\b/i.test(name)) {
    return `Step ${side} back, close ${other} beside ${side}, step ${side} forward.`;
  }

  if (/^Coaster Cross\b/i.test(name)) {
    return `Step ${side} back, close ${other} beside ${side}, cross ${side} over ${other}.`;
  }

  if (/^Shuffle Forward\b/i.test(name)) {
    return `Step ${side} forward, close ${other} beside ${side}, step ${side} forward.`;
  }

  if (/^Shuffle Back\b/i.test(name)) {
    return `Step ${side} back, close ${other} beside ${side}, step ${side} back.`;
  }

  if (/^Shuffle Turn\b/i.test(name)) {
    return `Turn ${turnDir} stepping ${side}-${other}-${side}.`;
  }

  if (/^Chasse\b/i.test(name)) {
    return `Step ${side} to ${side} side, close ${other} beside ${side}, step ${side} to ${side} side.`;
  }

  if (/^Step Lock Step Forward\b/i.test(name)) {
    return `Step ${side} forward, lock ${other} behind ${side}, step ${side} forward.`;
  }

  if (/^Step Lock Step Back\b/i.test(name)) {
    return `Step ${side} back, lock ${other} across ${side}, step ${side} back.`;
  }

  if (/^Pivot Turn\b/i.test(name)) {
    return `Step ${side} forward, pivot ${turnDir} taking weight onto ${other}.`;
  }

  if (/^Monterey Turn\b/i.test(name)) {
    return `Point ${side} to ${side} side, turn ${turnDir} closing ${side} beside ${other}, point ${other} to ${other} side, close ${other} beside ${side}.`;
  }

  if (/^Botafogo\b/i.test(name) || /\bBota Fogo\b/i.test(name)) {
    return `Cross ${side} over ${other}, rock ${other} to ${other} side, recover onto ${side}.`;
  }

  if (/^Travell?ing Botafogo\b/i.test(name)) {
    return `Cross ${side} over ${other}, step ${other} slightly to ${other} side, recover onto ${side} travelling forward.`;
  }

  if (/^Criss Cross Botafogo\b/i.test(name)) {
    return `Cross ${side} over ${other}, rock ${other} to ${other} side, recover onto ${side} with the body travelling across.`;
  }

  if (/^Contra Botafogo\b/i.test(name)) {
    return `Cross ${side} over ${other}, rock ${other} to ${other} side, recover onto ${side} in contra body position.`;
  }

  if (/^Same Foot Botafogo\b/i.test(name)) {
    return `Cross ${side} over ${other}, rock ${other} to ${other} side, recover onto ${side}, ready to repeat from the same-foot family.`;
  }

  if (/^Samba Whisk\b/i.test(name)) {
    return `Step ${side} to ${side} side, rock ${other} slightly behind ${side}, recover onto ${side}.`;
  }

  if (/^Samba Walk Stationary\b/i.test(name) || /^Stationary Samba Walk\b/i.test(name)) {
    return `Step ${side} forward, rock ${other} back on ball, recover onto ${side}.`;
  }

  if (/^Samba Walk Promenade\b/i.test(name) || /^Promenade Samba Walk\b/i.test(name)) {
    return `Step ${side} forward in promenade, rock ${other} back on ball, recover onto ${side}.`;
  }

  if (/^Samba Walk Side\b/i.test(name) || /^Side Samba Walk\b/i.test(name)) {
    return `Step ${side} slightly forward on ${side} diagonal, rock ${other} back on ball, recover onto ${side}.`;
  }

  if (/^Volta Travell?ing\b/i.test(name) || /^Travell?ing Volta\b/i.test(name)) {
    return `Cross ${side} over ${other}, step ${other} slightly to ${other} side on ball, repeat travelling ${turnDir}.`;
  }

  if (/^Volta Spot Continuous\b/i.test(name) || /^Continuous Solo Spot Volta\b/i.test(name)) {
    return `Turn ${turnDir} in place with repeated crossed samba steps, starting ${side}.`;
  }

  if (/^Volta Spot\b/i.test(name) || /^Solo Spot Volta\b/i.test(name)) {
    return `Turn ${turnDir} in place using small crossed samba steps, starting ${side}.`;
  }

  if (/^Volta Circular Solo\b/i.test(name) || /^Solo Circular Volta\b/i.test(name)) {
    return `Travel in a small circle turning ${turnDir} with crossed volta steps, starting ${side}.`;
  }

  if (/^Volta Circular\b/i.test(name) || /^Circular Volta\b/i.test(name)) {
    return `Travel in a circle turning ${turnDir} with crossed volta steps, starting ${side}.`;
  }

  if (/^Volta Shadow Circular\b/i.test(name) || /^Shadow Circular Volta\b/i.test(name)) {
    return `Travel in shadow position in a circle turning ${turnDir} with crossed volta steps, starting ${side}.`;
  }

  if (/^Volta Shadow Travell?ing\b/i.test(name) || /^Shadow Travell?ing Volta\b/i.test(name)) {
    return `Travel in shadow position turning ${turnDir} with crossed volta steps, starting ${side}.`;
  }

  if (/^Volta Dropped\b/i.test(name) || /^Dropped Volta\b/i.test(name)) {
    return `Execute dropped volta action turning ${turnDir} with crossed samba steps, starting ${side}.`;
  }

  if (/^Cruzados Walk\b/i.test(name) || /^Cruzado Walk\b/i.test(name)) {
    return `Walk ${side} forward slightly across the line of ${other}, keeping the samba bounce.`;
  }

  if (/^Cruzados Lock Continuous\b/i.test(name) || /^Continuous Cruzados Lock\b/i.test(name)) {
    return `Step ${side} forward, lock ${other} behind ${side}, repeat continuously with samba bounce.`;
  }

  if (/^Cruzados Lock\b/i.test(name) || /^Cruzado Lock\b/i.test(name)) {
    return `Step ${side} forward, lock ${other} behind ${side}, step ${side} forward with samba bounce.`;
  }

  if (/^Promenade Runs Samba\b/i.test(name)) {
    return `Run ${side}-${other}-${side} through promenade to counter-promenade action.`;
  }

  if (/^Carioca Runs Samba\b/i.test(name)) {
    return `Run quickly with carioca action, crossing and opening through the hips, starting ${side}.`;
  }

  if (/^Argentine Crosses Samba\b/i.test(name)) {
    return `Cross and replace weight with compact samba action, starting ${side}.`;
  }

  return null;
};


