const enrichCopperKnobGlossary = (entries) => {
  return entries.map((entry) => {
    const improvedDesc = buildCopperKnobDescription(entry);
    return improvedDesc ? { ...entry, desc: improvedDesc } : entry;
  });
};

const FOOT_LABELS = { L: 'Left', R: 'Right' };


const stripPlacementFluff = (desc = '') => {
  if (!desc) return desc;
  return String(desc)
    .replace(/\b(aggressively|fluidly|smoothly|entirely|firmly|cleanly|heavily|sharply|slightly|strongly|intentionally|forcefully|rigidly|tightly|quickly)\b/gi, '')
    .replace(/\s+,/g, ',')
    .replace(/\s+\./g, '.')
    .replace(/\s{2,}/g, ' ')
    .trim();
};

