  if (/^Natural Turn Waltz Right$/i.test(name)) return 'Turn right stepping right forward, step left to left side continuing the turn, close right beside left. Continue the second half with left back, right to side, close left beside right.';
  if (/^Reverse Turn Waltz Left$/i.test(name)) return 'Turn left stepping left to left side, step right back continuing the turn, close left beside right. Continue the second half with right forward, left to side, close right beside left.';
  if (/^Reverse Turn Waltz Right$/i.test(name)) return 'Turn right stepping right to right side, step left back continuing the turn, close right beside left. Continue the second half with left forward, right to side, close left beside right.';

  if (/^Boogie Left$/i.test(name)) return 'Keep weight on right foot and lift or roll the left hip and knee.';
  if (/^Boogie Right$/i.test(name)) return 'Keep weight on left foot and lift or roll the right hip and knee.';
  if (/^Boogie Roll Left$/i.test(name)) return 'Keep weight on right foot and roll the left hip in a circle.';
  if (/^Boogie Roll Right$/i.test(name)) return 'Keep weight on left foot and roll the right hip in a circle.';
  if (/^Boogie Walk Left$/i.test(name)) return 'Step left forward with a lifted left hip action.';
  if (/^Boogie Walk Right$/i.test(name)) return 'Step right forward with a lifted right hip action.';
